import { useEffect, useState } from "react";
import { OdsAlert } from "@/components/orderly/OdsAlert";
import { OdsButton } from "@/components/orderly/OdsButton";
import { OdsMetricCard } from "@/components/orderly/OdsMetricCard";
import {
  OdsSegmentedControl,
  type OdsSegmentedControlItem,
} from "@/components/orderly/OdsSegmentedControl";
import { ArrowUpRight, ExternalLink, RefreshCw } from "lucide-react";
import {
  fetchDexLeaderboard,
  fetchDexStats,
  type DexLeaderboardRow,
  type DexPeriod,
  type DexStats,
} from "@/services/orderly";
import { PaginationControls } from "@/components/PaginationControls";
import { type PublicSession, getPublicSession } from "@/utils/session";
import { LocalizedLink, useLocalizedNavigate } from "@/utils/localizedRoute";
import { useTranslation } from "@/i18n";
import {
  formatCurrency,
  getBrokerId,
  getDexName,
  getFee,
  getVolume,
  DexLogo,
  DexToken,
  LeaderboardCard,
} from "@/components/leaderboard/LeaderboardCard";

type LeaderboardSort = "volume" | "fee";
type TranslationFn = ReturnType<typeof useTranslation>["t"];

const DEX_PERIODS: DexPeriod[] = ["daily", "weekly", "30d", "90d"];

function getPeriodLabel(period: DexPeriod, t: TranslationFn): string {
  if (period === "daily") return t("board.period.daily");
  if (period === "weekly") return t("board.period.weekly");
  if (period === "30d") return t("board.period.30d");
  return t("board.period.90d");
}

function DexLaunchLink({
  dex,
  label,
}: {
  dex: DexLeaderboardRow;
  label: string;
}) {
  if (!dex.dexUrl)
    return <span className="text-xs text-(--fg-secondary)">—</span>;

  return (
    <a
      href={dex.dexUrl}
      target="_blank"
      rel="noopener noreferrer"
      onClick={event => event.stopPropagation()}
      className="inline-flex items-center gap-1.5 rounded-full border border-(--line-subtle) px-3 py-1.5 text-xs font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
    >
      {label}
      <ExternalLink className="h-3.5 w-3.5" />
    </a>
  );
}

function SkeletonBlock({ className = "" }: { className?: string }) {
  return (
    <div className={`animate-pulse rounded-lg bg-(--bg-hover) ${className}`} />
  );
}

function LeaderboardSkeleton() {
  return (
    <div className="overflow-x-auto">
      <table className="w-full min-w-[1080px]">
        <thead>
          <tr className="border-b border-(--line-subtle)">
            {Array.from({ length: 7 }).map((_, index) => (
              <th key={index} className="px-4 py-3 text-left">
                <SkeletonBlock className="h-3 w-16" />
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {Array.from({ length: 8 }).map((_, rowIndex) => (
            <tr
              key={rowIndex}
              className="border-b border-(--line-subtle) last:border-b-0"
            >
              <td className="px-4 py-4">
                <SkeletonBlock className="h-4 w-10" />
              </td>
              <td className="px-4 py-4">
                <div className="flex items-center gap-3">
                  <SkeletonBlock className="h-8 w-8 rounded-xl" />
                  <div>
                    <SkeletonBlock className="mb-2 h-4 w-28" />
                    <SkeletonBlock className="h-3 w-44" />
                  </div>
                </div>
              </td>
              <td className="px-4 py-4">
                <SkeletonBlock className="h-8 w-28" />
              </td>
              <td className="px-4 py-4">
                <SkeletonBlock className="ml-auto h-4 w-20" />
              </td>
              <td className="px-4 py-4">
                <SkeletonBlock className="ml-auto h-4 w-20" />
              </td>
              <td className="px-4 py-4">
                <SkeletonBlock className="ml-auto h-4 w-20" />
              </td>
              <td className="px-4 py-4">
                <SkeletonBlock className="ml-auto h-4 w-12" />
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function TopThreeSkeleton() {
  return (
    <div className="mb-8 grid gap-4 lg:grid-cols-3">
      {Array.from({ length: 3 }).map((_, index) => (
        <div
          key={index}
          className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5"
        >
          <div className="mb-6 flex items-start justify-between gap-4">
            <SkeletonBlock className="h-14 w-14 rounded-xl" />
            <SkeletonBlock className="h-8 w-12 rounded-full" />
          </div>
          <SkeletonBlock className="mb-3 h-6 w-36" />
          <SkeletonBlock className="mb-2 h-4 w-full" />
          <SkeletonBlock className="h-4 w-3/4" />
          <div className="mt-5 grid grid-cols-2 gap-3">
            <div>
              <SkeletonBlock className="mb-2 h-3 w-20" />
              <SkeletonBlock className="h-6 w-24" />
            </div>
            <div>
              <SkeletonBlock className="mb-2 h-3 w-24" />
              <SkeletonBlock className="h-6 w-24" />
            </div>
          </div>
          <div className="mt-5 flex items-center justify-between gap-3 border-t border-(--line-subtle) pt-4">
            <SkeletonBlock className="h-8 w-28" />
            <SkeletonBlock className="h-7 w-28 rounded-full" />
          </div>
        </div>
      ))}
    </div>
  );
}

export default function BoardPage() {
  const { t } = useTranslation();
  const navigate = useLocalizedNavigate();
  const [rows, setRows] = useState<DexLeaderboardRow[]>([]);
  const [rowMeta, setRowMeta] = useState({ total: 0, limit: 20, offset: 0 });
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(20);
  const [topThree, setTopThree] = useState<DexLeaderboardRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [stats, setStats] = useState<DexStats | null>(null);
  const [statsError, setStatsError] = useState<string | null>(null);
  const [leaderboardSort, setLeaderboardSort] =
    useState<LeaderboardSort>("volume");
  const [leaderboardPeriod, setLeaderboardPeriod] = useState<DexPeriod>("30d");
  const [refreshNonce, setRefreshNonce] = useState(0);
  const [publicSession, setPublicSession] = useState<PublicSession>(() =>
    getPublicSession()
  );

  useEffect(() => {
    function refreshSession() {
      setPublicSession(getPublicSession());
    }

    window.addEventListener("authChanged", refreshSession);
    window.addEventListener("profileUpdated", refreshSession);
    window.addEventListener("storage", refreshSession);
    return () => {
      window.removeEventListener("authChanged", refreshSession);
      window.removeEventListener("profileUpdated", refreshSession);
      window.removeEventListener("storage", refreshSession);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    const shouldShowInitialLoading = rows.length === 0;
    setLoading(shouldShowInitialLoading);
    setRefreshing(!shouldShowInitialLoading);
    setError(null);
    fetchDexLeaderboard({
      sort: leaderboardSort,
      period: leaderboardPeriod,
      limit: pageSize,
      offset: (page - 1) * pageSize,
    })
      .then(({ rows: data, meta }) => {
        if (!cancelled) {
          setRows(data);
          setRowMeta(meta);
        }
      })
      .catch(err => {
        if (!cancelled)
          setError(
            err instanceof Error ? err.message : t("board.errorLoadLeaderboard")
          );
      })
      .finally(() => {
        if (!cancelled) {
          setLoading(false);
          setRefreshing(false);
        }
      });
    return () => {
      cancelled = true;
    };
  }, [leaderboardPeriod, leaderboardSort, page, pageSize, refreshNonce]);

  useEffect(() => {
    let cancelled = false;
    setStatsError(null);
    fetchDexStats(leaderboardPeriod)
      .then(data => {
        if (!cancelled) setStats(data);
      })
      .catch(err => {
        if (!cancelled)
          setStatsError(
            err instanceof Error ? err.message : t("board.errorLoadStats")
          );
      });
    return () => {
      cancelled = true;
    };
  }, [leaderboardPeriod, refreshNonce]);

  useEffect(() => {
    let cancelled = false;
    fetchDexLeaderboard({
      sort: leaderboardSort,
      period: leaderboardPeriod,
      limit: 3,
      offset: 0,
    })
      .then(({ rows: data }) => {
        if (!cancelled) setTopThree(data);
      })
      .catch(() => {
        if (!cancelled) setTopThree([]);
      });
    return () => {
      cancelled = true;
    };
  }, [leaderboardPeriod, leaderboardSort, refreshNonce]);

  useEffect(() => {
    setPage(1);
  }, [leaderboardPeriod, leaderboardSort]);

  const leaderboardPeriodLabel = getPeriodLabel(leaderboardPeriod, t);
  const leaderboardSortItems: ReadonlyArray<
    OdsSegmentedControlItem<LeaderboardSort>
  > = [
    { value: "volume", label: t("board.sortByVolume") },
    { value: "fee", label: t("board.sortByFee") },
  ];
  const leaderboardPeriodItems: ReadonlyArray<
    OdsSegmentedControlItem<DexPeriod>
  > = DEX_PERIODS.map(period => ({
    value: period,
    label: getPeriodLabel(period, t),
  }));
  const socialLabels = {
    website: t("board.website"),
    telegram: "Telegram",
    discord: "Discord",
    x: "X",
    dex: "DEX",
  };
  const isInitialLoading = loading && rows.length === 0;
  const showRefreshSkeleton = refreshing && rows.length > 0;
  const blockingError = error && rows.length === 0;
  const getDetailHref = (dex: DexLeaderboardRow) =>
    `/board/${encodeURIComponent(getBrokerId(dex))}?period=${leaderboardPeriod}&sort=${leaderboardSort}`;

  return (
    <div className="min-h-screen bg-(--bg-base)">
      <section className="relative overflow-hidden px-6 py-12">
        <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_top,var(--bg-brand-subtle),transparent_58%)]" />
        <div className="relative mx-auto max-w-[1100px]">
          <div className="mb-8">
            <div className="max-w-[760px]">
              <h1 className="max-w-[720px] text-4xl font-semibold leading-tight text-(--fg-primary) sm:text-5xl">
                {t("board.heroTitle")}
              </h1>
              <p className="mt-4 max-w-[620px] text-base leading-7 text-(--fg-secondary)">
                {t("board.heroDescription")}
              </p>
              <div className="mt-6 flex flex-col items-start gap-3">
                {publicSession.isAmbassadorDistributor ? (
                  <button
                    type="button"
                    disabled
                    className="inline-flex w-fit cursor-not-allowed items-center gap-2 rounded-full border border-(--line-subtle) px-6 py-3 text-sm font-medium text-(--fg-secondary) opacity-70"
                  >
                    {t("landing.notApplicable")}
                  </button>
                ) : (
                  <OdsButton
                    asChild
                    className="w-fit gap-2"
                    size="large"
                    variant="highlight"
                  >
                    <LocalizedLink
                      to={
                        publicSession.isLoggedIn
                          ? publicSession.dashboardPath
                          : "/login"
                      }
                    >
                      {publicSession.isLoggedIn
                        ? t("landing.goToDashboard")
                        : t("board.launchYourDex")}
                      <ArrowUpRight className="h-4 w-4" />
                    </LocalizedLink>
                  </OdsButton>
                )}
                <span className="text-sm text-(--fg-secondary)">
                  {t("board.heroFootnote")}
                </span>
              </div>
            </div>
          </div>

          <div className="mb-8 grid gap-4 md:grid-cols-2">
            {stats ? (
              <>
                <OdsMetricCard
                  label={t("board.totalDexes")}
                  value={stats.total.allTime.toLocaleString()}
                  sub={
                    statsError
                      ? t("board.statsUnavailable")
                      : t("board.newCount", {
                          count: stats.total.new.toLocaleString(),
                          period: leaderboardPeriodLabel,
                        })
                  }
                  subTone={statsError ? "muted" : "positive"}
                />
                <OdsMetricCard
                  label={t("board.graduated")}
                  value={stats.graduated.allTime.toLocaleString()}
                  sub={
                    statsError
                      ? t("board.statsUnavailable")
                      : t("board.newCount", {
                          count: stats.graduated.new.toLocaleString(),
                          period: leaderboardPeriodLabel,
                        })
                  }
                  subTone={statsError ? "muted" : "positive"}
                />
              </>
            ) : (
              <>
                <div className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5">
                  <SkeletonBlock className="mb-3 h-3 w-24" />
                  <SkeletonBlock className="mb-2 h-8 w-28" />
                  <SkeletonBlock className="h-3 w-32" />
                </div>
                <div className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5">
                  <SkeletonBlock className="mb-3 h-3 w-24" />
                  <SkeletonBlock className="mb-2 h-8 w-20" />
                  <SkeletonBlock className="h-3 w-32" />
                </div>
              </>
            )}
          </div>

          {showRefreshSkeleton ? (
            <TopThreeSkeleton />
          ) : !blockingError && topThree.length > 0 ? (
            <div className="mb-8 grid gap-4 lg:grid-cols-3">
              {topThree.map((dex, index) => (
                <LeaderboardCard
                  key={dex.id || getBrokerId(dex)}
                  dex={dex}
                  rank={index + 1}
                  href={getDetailHref(dex)}
                  labels={{
                    ...socialLabels,
                    unnamedDex: t("board.unnamedDex"),
                    noDescription: t("board.noDescription"),
                    volumeForPeriod: t("board.volumeForPeriod", {
                      period: leaderboardPeriodLabel,
                    }),
                    builderRevenue: t("board.builderRevenue"),
                  }}
                />
              ))}
            </div>
          ) : null}

          <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <OdsSegmentedControl
              ariaLabel={t("board.leaderboardSort")}
              items={leaderboardSortItems}
              onValueChange={setLeaderboardSort}
              value={leaderboardSort}
            />
            <div className="flex flex-wrap items-center justify-end gap-2">
              <OdsSegmentedControl
                ariaLabel={t("board.leaderboardPeriod")}
                items={leaderboardPeriodItems}
                onValueChange={setLeaderboardPeriod}
                value={leaderboardPeriod}
              />
              <button
                type="button"
                onClick={() => setRefreshNonce(value => value + 1)}
                disabled={loading || refreshing}
                className="inline-flex items-center gap-1.5 rounded-full border border-(--line-subtle) px-3 py-1.5 text-xs font-semibold text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary) disabled:cursor-not-allowed disabled:opacity-60"
              >
                <RefreshCw
                  className={`h-3.5 w-3.5 ${loading || refreshing ? "animate-spin" : ""}`}
                />
                {t("common.refresh")}
              </button>
            </div>
          </div>

          {error && rows.length > 0 && (
            <OdsAlert className="mb-4" type="negative">
              {error}
            </OdsAlert>
          )}

          <div className="overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary)">
            {isInitialLoading || showRefreshSkeleton ? (
              <LeaderboardSkeleton />
            ) : blockingError ? (
              <div className="p-12 text-center text-sm text-(--fg-negative)">
                {blockingError}
              </div>
            ) : (
              <>
                <div className="overflow-x-auto">
                  <table className="w-full min-w-[1080px]">
                    <thead>
                      <tr className="border-b border-(--line-subtle)">
                        <th className="px-4 py-3 text-left text-xs font-medium text-(--fg-secondary)">
                          {t("board.rank")}
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-(--fg-secondary)">
                          DEX
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-(--fg-secondary)">
                          {t("common.token")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.volumeForPeriod", {
                            period: leaderboardPeriodLabel,
                          })}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.builderRevenue")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.totalFee")}
                        </th>
                        <th
                          className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)"
                          aria-label={t("board.openDex")}
                        />
                      </tr>
                    </thead>
                    <tbody>
                      {rows.map((dex, rowIndex) => {
                        const name = getDexName(dex, t("board.unnamedDex"));
                        return (
                          <tr
                            key={dex.id || getBrokerId(dex)}
                            onClick={() => navigate(getDetailHref(dex))}
                            className="cursor-pointer border-b border-(--line-subtle) transition-colors last:border-b-0 hover:bg-(--bg-hover)"
                          >
                            <td className="px-4 py-4 text-sm font-semibold text-(--fg-primary)">
                              #{(page - 1) * pageSize + rowIndex + 1}
                            </td>
                            <td className="px-4 py-4">
                              <div className="flex items-center gap-3">
                                <DexLogo dex={dex} size="sm" />
                                <div>
                                  <LocalizedLink
                                    to={getDetailHref(dex)}
                                    className="text-sm font-medium text-(--fg-primary) hover:text-(--fg-brand)"
                                  >
                                    {name}
                                  </LocalizedLink>
                                  <div className="max-w-[260px] truncate text-xs text-(--fg-secondary)">
                                    {dex.description || "—"}
                                  </div>
                                </div>
                              </div>
                            </td>
                            <td className="px-4 py-4">
                              <DexToken dex={dex} />
                            </td>
                            <td className="px-4 py-4 text-right text-sm font-semibold text-(--fg-primary)">
                              {formatCurrency(getVolume(dex))}
                            </td>
                            <td className="px-4 py-4 text-right text-sm font-semibold text-gradient-positive">
                              {formatCurrency(getFee(dex))}
                            </td>
                            <td className="px-4 py-4 text-right text-sm text-(--fg-secondary)">
                              {formatCurrency(dex.totalFee)}
                            </td>
                            <td className="px-4 py-4 text-right">
                              <DexLaunchLink
                                dex={dex}
                                label={t("board.openDex")}
                              />
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
                <PaginationControls
                  page={page}
                  pageSize={pageSize}
                  total={rowMeta.total}
                  onPageChange={setPage}
                  onPageSizeChange={size => {
                    setPageSize(size);
                    setPage(1);
                  }}
                  loading={loading}
                  i18nPrefix="board"
                />
              </>
            )}
          </div>
        </div>
      </section>
    </div>
  );
}
